import{toDependency}from"../../util/input.js";import{hasDependency}from"../../util/plugin.js";const title="React Native",enablers=["react-native"],isEnabled=({dependencies:e})=>hasDependency(e,enablers),config=["react-native.config.js"],RN_CLI_PACKAGES=["@react-native-community/cli","@react-native-community/cli-platform-android","@react-native-community/cli-platform-ios"],resolveConfig=async e=>{const n=[];if(e.dependencies)for(const t of Object.keys(e.dependencies))n.push(toDependency(t));if(e.platforms)for(const t of Object.values(e.platforms))t.npmPackageName&&n.push(toDependency(t.npmPackageName));return n},resolve=()=>RN_CLI_PACKAGES.map(e=>toDependency(e,{optional:!0})),plugin={title:title,enablers:enablers,isEnabled:isEnabled,config:config,resolveConfig:resolveConfig,resolve:resolve};export default plugin;